-- PetCare E14 protected platform operators, safe tenant directory, and lifecycle controls.
create table public.platform_role_definitions(role_key text primary key check(role_key in('platform_admin','platform_support','platform_auditor')),display_name text not null,requires_mfa boolean not null default true);
insert into public.platform_role_definitions values('platform_admin','Platform administrator',true),('platform_support','Platform support',true),('platform_auditor','Platform auditor',true);
create table public.platform_permission_definitions(permission_key text primary key check(permission_key in('platform.businesses.read','platform.businesses.manage','platform.audit.read')),description text not null);
insert into public.platform_permission_definitions values('platform.businesses.read','View safe cross-tenant directory metadata.'),('platform.businesses.manage','Apply controlled tenant lifecycle changes.'),('platform.audit.read','Review platform administrative audit history.');
create table public.platform_role_permissions(role_key text not null references public.platform_role_definitions(role_key) on delete restrict,permission_key text not null references public.platform_permission_definitions(permission_key) on delete restrict,primary key(role_key,permission_key));
insert into public.platform_role_permissions values('platform_admin','platform.businesses.read'),('platform_admin','platform.businesses.manage'),('platform_admin','platform.audit.read'),('platform_support','platform.businesses.read'),('platform_auditor','platform.businesses.read'),('platform_auditor','platform.audit.read');
create table public.platform_operator_assignments(id uuid primary key default gen_random_uuid(),identity_id uuid not null references public.identity_profiles(id) on delete restrict,role_key text not null references public.platform_role_definitions(role_key) on delete restrict,status text not null default 'active' check(status in('active','suspended','revoked')),granted_reason text not null check(char_length(trim(granted_reason)) between 12 and 500),granted_at timestamptz not null default now(),revoked_at timestamptz,unique(identity_id,role_key),check((status='revoked')=(revoked_at is not null)));
create table public.platform_tenant_controls(business_id uuid primary key references public.businesses(id) on delete restrict,lifecycle_status text not null check(lifecycle_status in('setup','trial','active','restricted','suspended','closing','closed')),restriction_code text,restriction_reason text,changed_by uuid references public.identity_profiles(id) on delete restrict,changed_at timestamptz not null default now(),check((lifecycle_status in('restricted','suspended'))=(restriction_reason is not null)));
insert into public.platform_tenant_controls(business_id,lifecycle_status,restriction_code,restriction_reason) select id,case status when 'suspended' then 'suspended' when 'archived' then 'closed' when 'draft' then 'setup' else 'active' end,case when status='suspended' then 'migrated_state' end,case when status='suspended' then 'Migrated suspended tenant state.' end from public.businesses on conflict do nothing;
create or replace function app.initialize_platform_tenant_control() returns trigger language plpgsql security definer set search_path='' as $$begin insert into public.platform_tenant_controls(business_id,lifecycle_status) values(new.id,case when new.status='draft' then 'setup' else 'active' end) on conflict do nothing;return new;end;$$;
create trigger businesses_platform_control after insert on public.businesses for each row execute function app.initialize_platform_tenant_control();
create table public.platform_tenant_events(id uuid primary key default gen_random_uuid(),business_id uuid not null references public.businesses(id) on delete restrict,event_type text not null check(event_type in('control_initialized','lifecycle_changed')),from_status text,to_status text not null,reason text not null,actor_id uuid not null references public.identity_profiles(id) on delete restrict,occurred_at timestamptz not null default now(),idempotency_key text not null unique);
create trigger platform_tenant_events_immutable before update or delete on public.platform_tenant_events for each row execute function app.prevent_commercial_snapshot_change();

create or replace function app.platform_has_permission(permission_value text) returns boolean language sql security definer stable set search_path='' as $$select exists(select 1 from public.platform_operator_assignments a join public.platform_role_permissions rp on rp.role_key=a.role_key where a.identity_id=auth.uid() and a.status='active' and rp.permission_key=permission_value)$$;
create or replace function app.get_platform_context() returns jsonb language sql security definer stable set search_path='' as $$select case when exists(select 1 from public.platform_operator_assignments a where a.identity_id=auth.uid() and a.status='active') then jsonb_build_object('identity_id',auth.uid(),'roles',coalesce((select jsonb_agg(a.role_key order by a.role_key) from public.platform_operator_assignments a where a.identity_id=auth.uid() and a.status='active'),'[]'::jsonb),'permissions',coalesce((select jsonb_agg(distinct rp.permission_key) from public.platform_operator_assignments a join public.platform_role_permissions rp on rp.role_key=a.role_key where a.identity_id=auth.uid() and a.status='active'),'[]'::jsonb),'requires_mfa',true) else null end$$;
create or replace function app.grant_platform_operator(target_identity_id uuid,role_value text,reason_value text) returns uuid language plpgsql security definer set search_path='' as $$declare saved_id uuid;begin if role_value not in('platform_admin','platform_support','platform_auditor') or char_length(trim(coalesce(reason_value,'')))<12 then raise exception 'documented platform assignment required' using errcode='22023';end if;insert into public.platform_operator_assignments(identity_id,role_key,status,granted_reason,revoked_at) values(target_identity_id,role_value,'active',trim(reason_value),null) on conflict(identity_id,role_key) do update set status='active',granted_reason=excluded.granted_reason,granted_at=now(),revoked_at=null returning id into saved_id;return saved_id;end;$$;
create or replace function app.list_platform_tenants() returns jsonb language plpgsql security definer set search_path='' as $$begin if not app.platform_has_permission('platform.businesses.read') then raise exception 'platform tenant directory unavailable' using errcode='42501';end if;return coalesce((select jsonb_agg(jsonb_build_object('business_id',b.id,'name',b.name,'public_slug',b.public_slug,'business_status',b.status,'lifecycle_status',c.lifecycle_status,'restriction_code',c.restriction_code,'changed_at',c.changed_at,'location_count',(select count(*) from public.locations l where l.business_id=b.id and l.status<>'archived'),'active_member_count',(select count(*) from public.business_memberships m where m.business_id=b.id and m.state='active'),'created_at',b.created_at) order by b.created_at desc) from public.businesses b join public.platform_tenant_controls c on c.business_id=b.id),'[]'::jsonb);end;$$;
create or replace function app.transition_platform_tenant(target_business_id uuid,next_status_value text,restriction_code_value text,reason_value text,confirmation_value text,request_key text) returns uuid language plpgsql security definer set search_path='' as $$declare current_control public.platform_tenant_controls%rowtype;tenant public.businesses%rowtype;event_id uuid;begin if not app.platform_has_permission('platform.businesses.manage') then raise exception 'platform tenant control unavailable' using errcode='42501';end if;select id into event_id from public.platform_tenant_events where idempotency_key=trim(request_key);if event_id is not null then return event_id;end if;select * into tenant from public.businesses where id=target_business_id;select * into current_control from public.platform_tenant_controls where business_id=target_business_id for update;if tenant.id is null or next_status_value not in('active','restricted','suspended') or char_length(trim(coalesce(reason_value,'')))<12 or (next_status_value='suspended' and lower(trim(coalesce(confirmation_value,'')))<>tenant.public_slug) or (current_control.lifecycle_status,next_status_value) not in(('active','restricted'),('active','suspended'),('restricted','active'),('restricted','suspended'),('suspended','active'),('suspended','restricted')) then raise exception 'controlled tenant lifecycle transition required' using errcode='P0001';end if;update public.platform_tenant_controls set lifecycle_status=next_status_value,restriction_code=case when next_status_value='active' then null else nullif(trim(restriction_code_value),'') end,restriction_reason=case when next_status_value='active' then null else trim(reason_value) end,changed_by=auth.uid(),changed_at=now() where business_id=target_business_id;update public.businesses set status=case when next_status_value='suspended' then 'suspended' else 'active' end where id=target_business_id;insert into public.platform_tenant_events(business_id,event_type,from_status,to_status,reason,actor_id,idempotency_key) values(target_business_id,'lifecycle_changed',current_control.lifecycle_status,next_status_value,trim(reason_value),auth.uid(),trim(request_key)) returning id into event_id;return event_id;end;$$;

do $$declare n text;begin foreach n in array array['platform_role_definitions','platform_permission_definitions','platform_role_permissions','platform_operator_assignments','platform_tenant_controls','platform_tenant_events'] loop execute format('alter table public.%I enable row level security',n);execute format('alter table public.%I force row level security',n);execute format('revoke all on public.%I from anon,authenticated',n);end loop;end$$;
grant select on public.platform_operator_assignments,public.platform_tenant_controls,public.platform_tenant_events to authenticated;
create policy platform_assignments_self on public.platform_operator_assignments for select to authenticated using(identity_id=auth.uid());
create policy platform_controls_operator on public.platform_tenant_controls for select to authenticated using(app.platform_has_permission('platform.businesses.read'));
create policy platform_events_operator on public.platform_tenant_events for select to authenticated using(app.platform_has_permission('platform.audit.read'));
revoke all on function app.platform_has_permission(text),app.get_platform_context(),app.grant_platform_operator(uuid,text,text),app.list_platform_tenants(),app.transition_platform_tenant(uuid,text,text,text,text,text) from public;
grant execute on function app.platform_has_permission(text),app.get_platform_context(),app.list_platform_tenants(),app.transition_platform_tenant(uuid,text,text,text,text,text) to authenticated;
grant execute on function app.grant_platform_operator(uuid,text,text) to service_role;
